const text = String($json.message || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();

const rules = [
  { intent: 'HUMAN_HANDOFF', confidence: 0.97, rule: 'handoff_keywords', re: /(falar com humano|atendente|consultor|pessoa real|atendimento humano)/i },
  { intent: 'OPT_OUT', confidence: 0.99, rule: 'opt_out_keywords', re: /(\bparar\b|\bsair\b|nao me chama|nao quero mensagens|remover meu numero|descadastrar)/i },
  { intent: 'GREETING', confidence: 0.95, rule: 'greeting_keywords', re: /^(oi|ola|olá|bom dia|boa tarde|boa noite)\b/i },
  { intent: 'PRICING_INTEREST', confidence: 0.96, rule: 'pricing_keywords', re: /(preco|preço|valor|quanto custa|investimento|formas de pagamento)/i },
  { intent: 'STATUS_REQUEST', confidence: 0.95, rule: 'status_keywords', re: /(status|andamento|como esta meu processo|como está meu processo|meu processo)/i },
  { intent: 'SCHEDULING_INTENT', confidence: 0.96, rule: 'scheduling_keywords', re: /(agendar|marcar horario|marcar horário|agenda|marcar consulta)/i },
];

let match = rules.find(r => r.re.test(text));

return [{
  ...$json,
  detected_intent: match ? match.intent : 'UNKNOWN',
  intent_confidence: match ? match.confidence : 0.0,
  matched_rule: match ? match.rule : 'no_match',
  handled_by: match ? 'deterministic_router' : 'llm'
}];

const text = String($json.message || '').toLowerCase();
// Conservative specialist routing; fallback to NONE for ambiguity
const ragRe = /(lmd|lei da memoria democratica|documento|documentacao|certidao|certidão|prazo legal|elegibilidade)/i;
const schedulingRe = /(agendar|marcar horario|marcar horário|agenda|consulta)/i;
let specialist_route = 'NONE';
if (schedulingRe.test(text)) specialist_route = 'SCHEDULING_SPECIALIST';
else if (ragRe.test(text)) specialist_route = 'RAG_SPECIALIST';
return [{ ...$json, specialist_route, handled_by: specialist_route === 'NONE' ? ($json.handled_by || 'llm') : specialist_route.toLowerCase() }];

const items = $input.all().map(i => i.json).filter(j => j && j.content_text);
const hitCount = items.length;
const contextText = items.map((h, idx) => `[#${idx+1}] ${h.content_text}`).join('\n\n');
const confidence = hitCount >= 3 ? 0.9 : hitCount === 2 ? 0.75 : hitCount === 1 ? 0.55 : 0.0;
const base = { ...($json || {}) };
return [{ ...base, rag_hits_count: hitCount, rag_confidence: confidence, rag_context: contextText, rag_used: hitCount > 0, handled_by: 'rag_specialist' }];

