const text=String($json.message||'').toLowerCase();
let score=10;
const reasons=[];
if ((String($json.detected_intent||'')==='PRICING_INTEREST') || /preco|preço|valor|quanto custa|contratar/.test(text)){score+=35;reasons.push('pricing_interest');}
if (/urgente|hoje|agora|prioridade/.test(text)){score+=20;reasons.push('urgency');}
if (String($json.detected_intent||'')==='HUMAN_HANDOFF'){score+=15;reasons.push('handoff_request');}
if ((Number($json.rag_hits_count||0))>0){score+=10;reasons.push('qualified_question');}
if ((Number($json.followup_stage||0))>=1){score+=5;reasons.push('engaged_followup');}
if (score>100) score=100;
const temp=score>=70?'hot':score>=40?'warm':'cold';
const priority=score>=70?'p1':score>=40?'p2':'p3';
return [{...$json,lead_score:score,lead_temperature:temp,priority_level:priority,lead_score_reasons:reasons}];

const msg=String($json.message||'');
const rules=[];
let fail=false;
if(!msg.trim()){fail=true;rules.push('empty_message');}
if(msg.length>800){fail=true;rules.push('message_too_long');}
if(msg.includes('{{')||msg.includes('undefined')||msg.includes('[object Object]')){fail=true;rules.push('broken_placeholder');}
if(/garantimos|garantia de resultado|atalho legal|jeitinho/.test(msg.toLowerCase())){fail=true;rules.push('forbidden_promise');}
const st=$node['Get state pre-send'].json||{};
if(st.opt_out===true||String(st.opt_out)==='true'){fail=true;rules.push('opt_out_block');}
const sup=$node['Check suppression list'].json||{};
if(sup.id){fail=true;rules.push('suppression_block');}
const outboundCount=$items('Get recent outbound count').length;
if(outboundCount>=5){fail=true;rules.push('rate_limit_block');}
const recentFailures=$items('Get recent provider failures').length;
if(recentFailures>=4){fail=true;rules.push('circuit_breaker_open');}
return [{...$json,qa_status: fail?'fail':'pass',qa_fail_reason: rules[0]||'',qa_rules_triggered:rules,qa_message_limit:800}];
